import{_ as t,c as e,o as d,V as a}from"./chunks/framework.Wg2ruw7m.js";const g=JSON.parse('{"title":"Grid","description":"","frontmatter":{},"headers":[],"relativePath":"guide/css/常见布局/grid.md","filePath":"guide/css/常见布局/grid.md","lastUpdated":1717823777000}'),r={name:"guide/css/常见布局/grid.md"},i=a('<h1 id="grid" tabindex="-1">Grid <a class="header-anchor" href="#grid" aria-label="Permalink to &quot;Grid&quot;">​</a></h1><p><code>Grid</code> 网格布局</p><h2 id="grid布局和flex布局" tabindex="-1">Grid布局和flex布局 <a class="header-anchor" href="#grid布局和flex布局" aria-label="Permalink to &quot;Grid布局和flex布局&quot;">​</a></h2><p>flex布局和grad布局有实质的区别：</p><ul><li>flex布局是一维布局 <ul><li>flex布局一次只能处理一个维度上的元素布局，一行或一列。</li></ul></li><li>grid布局是二维布局 <ul><li>grid布局是将容器划分成了 <code>行</code> 和 <code>列</code>，产生了一个个的网格。</li></ul></li></ul><h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><table><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>container</td><td>容器</td></tr><tr><td>items</td><td>项目</td></tr><tr><td>row</td><td>行</td></tr><tr><td>column</td><td>列</td></tr><tr><td>gap</td><td>间距</td></tr><tr><td>area</td><td>区域</td></tr><tr><td>content</td><td>内容</td></tr></tbody></table><p>Grid布局属性可以分为两大类：容器属性和项目属性</p><h2 id="容器属性" tabindex="-1">容器属性 <a class="header-anchor" href="#容器属性" aria-label="Permalink to &quot;容器属性&quot;">​</a></h2><p>声明 <code>display: grid</code> 则该容器是一个块级元素</p><p>声明 <code>display: inline-grid</code> 则容器元素为行内元素</p><p>注意：设为网格布局以后，容器子元素（项目）的 <code>float</code>、<code>display: inline-block</code>、<code>display: table-cell</code>、<code>vertical-align</code>、<code>column-*</code>等设置都将失效。</p><h2 id="项目属性" tabindex="-1">项目属性 <a class="header-anchor" href="#项目属性" aria-label="Permalink to &quot;项目属性&quot;">​</a></h2><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',14),l=[i];function o(c,s,n,h,p,u){return d(),e("div",null,l)}const m=t(r,[["render",o]]);export{g as __pageData,m as default};
